-- ----------------------------
-- Table structure for devices
-- ----------------------------
DROP TABLE IF EXISTS `devices`;
CREATE TABLE `devices` (
  `id` int NOT NULL COMMENT '序号',
  `type_name` varchar(255) DEFAULT NULL COMMENT '设备类型',
  `asset_id` varchar(255) NOT NULL COMMENT '设备id',
  `asset_name` varchar(255) DEFAULT NULL COMMENT '设备名称',
  `obtain_time` varchar(255) DEFAULT NULL COMMENT '获取时间',
  `user` varchar(255) DEFAULT NULL COMMENT '使用人',
  `department` varchar(255) DEFAULT NULL COMMENT '使用/管理部门',
  `storage_location` varchar(255) DEFAULT NULL COMMENT '存放地点',
  `manufacturer` varchar(255) DEFAULT NULL COMMENT '厂家',
  `brand` varchar(255) DEFAULT NULL COMMENT '品牌',
  `specification` varchar(255) DEFAULT NULL COMMENT '规格型号',
  `create_user` varchar(255) DEFAULT NULL COMMENT '制单人',
  `create_time` varchar(255) DEFAULT NULL COMMENT '制单时间',
  `manager` varchar(255) DEFAULT NULL COMMENT '经办人',
  `supplier` varchar(255) DEFAULT NULL COMMENT '供货商',
  `contract_no` varchar(255) DEFAULT NULL COMMENT '合同号',
  `factory_no` varchar(255) DEFAULT NULL COMMENT '出厂号',
  `old_storage_location` varchar(255) DEFAULT NULL COMMENT '原存放地点',
  `old_user` varchar(255) DEFAULT NULL COMMENT '原使用人',
  `old_manager` varchar(255) DEFAULT NULL COMMENT '原经办人',
  PRIMARY KEY (`asset_id`),
  UNIQUE KEY `devices_pk` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='设备信息表';

